export type SessionStatus =
  | 'BOOTSTRAPPING'
  | 'GUEST'
  | 'AUTHENTICATED_USER'
  | 'AUTHENTICATED_BUSINESS'
  | 'AUTHENTICATED_ADMIN'
  | 'SESSION_RECOVERY'
  | 'SESSION_INVALID';

