  | 'submit_code'
  | 'vote_code'
  | 'report_bathroom'
  | 'add_bathroom'
  | 'claim_business'
  | 'rate_cleanliness';

export type ReplayStrategy = 'immediate_after_auth' | 'user_confirm' | 'draft_resume';

export interface ReturnIntent {
  intent_id: string;
  type: IntentType;
  route: string;
  params: Record<string, unknown>;
  created_at: string;
  replay_strategy: ReplayStrategy;
}

/**
 * Options passed to AuthContext.requireAuth().
