  id: string;
  type: MutationType;
  payload: Record<string, unknown>;
  created_at: string;
  retry_count: number;
  last_attempt_at: string | null;
  user_id: string;
}

export interface QueueProcessResult {
  processed_count: number;
  dropped_count: number;
  pending_count: number;
}

// ============================================================================
// DRAFT TYPES
