    onMutate: async (payload: TPayload): Promise<MutationContext> => {
      const store = useAuthStore.getState();
      const userId = store.user?.id;

      const baseContext: MutationContext = {
        userIdAtInvocation: userId ?? '',
        snapshots: [],
        invalidationKeys: [],
        earlyOutcome: null,
