          console.warn('[useOfflineMutation] Auth/RLS error:', error);
          return 'auth_required';
        }

        if (isTransientNetworkError(error)) {
          // Transient failure â€” enqueue for offline replay
          const queueId = await offlineQueue.enqueue(mutationType, payload, userId);
          console.log(`[useOfflineMutation] Network error â€” queued ${queueId}`);
          return 'queued_retry';
        }

        // Non-retryable business/validation error â€” propagate to onError
        throw error instanceof Error ? error : new Error(String(error));
