    if (isFlushing.current) return;
    if (!userId || !isAuthenticated) return;

    isFlushing.current = true;

    try {
      const result = await flushOfflineQueue({
        queryClient,
        activeUserId: userId,
        refreshUser,
        onFlushComplete: (res) => {
          if (res.processed > 0) {
            console.log(
              `[useOfflineSync] Flushed ${res.processed} item(s)` +
                (res.stopped ? ` (stopped: ${res.stopReason})` : '')
            );
            // TODO: Toast notification â€” batch, once per flush cycle
            // Example: Toast.show(`${res.processed} action(s) synced`);
          }
        },
        onAuthChanged: () => {
          console.warn('[useOfflineSync] Auth changed mid-flush â€” aborting');
        },
      });

