// â”€â”€ Context shape â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

interface AuthContextValue {
  signIn: (email: string, password: string) => Promise<{ error: AuthError | null }>;
  signUp: (
    email: string,
    password: string,
    displayName?: string
  ) => Promise<{ error: AuthError | null; needsEmailConfirmation?: boolean }>;
  signOut: () => Promise<void>;
  refreshProfile: () => Promise<void>;
  refreshUser: () => Promise<void>;
  /**
   * Synchronous guest gate.
   * Returns true â†’ caller is authenticated, may proceed.
   * Returns false â†’ user is a guest; intent persisted in store; caller MUST navigate to login.
   */
  requireAuth: (intent?: RequireAuthIntent) => boolean;
  /** Read the pending return intent without consuming it. */
  peekReturnIntent: () => ReturnIntent | null;
  /** Consume (read + clear) the pending return intent. Returns it or null. */
  consumeReturnIntent: () => ReturnIntent | null;
  /** Clear the pending return intent without reading it. */
  clearReturnIntent: () => void;
}

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

export function useAuthContext(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuthContext must be used inside AuthProvider');
  return ctx;
}

